const tool = $input.item.json.tool;
const args = $input.item.json.args ?? {};
const sseUrl = $vars.FORGEJO_MCP_SSE_URL;
const verifySSL = ($vars.FORGEJO_VERIFY_SSL ?? 'false') !== 'false';

if (!tool) throw new Error('tool parameter is required');
if (!sseUrl) throw new Error('FORGEJO_MCP_SSE_URL workflow variable is not set');

// Build MCP call payload (JSON-RPC 2.0 over HTTP)
const payload = {
  jsonrpc: '2.0',
  method: 'tools/call',
  params: { name: tool, arguments: args },
  id: crypto.randomUUID()
};

return [{ json: { payload, sseUrl, verifySSL } }];

const response = $input.item.json;
if (response.error) {
  throw new Error(`forgejo-mcp error [${response.error.code}]: ${response.error.message}`);
}
const result = response.result ?? response;
return [{ json: { status: 'ok', result, tool: $('Sub — Input (tool + args)').first().json.tool } }];
